CREATE OR REPLACE FUNCTION "edfi"."TF_TR_AcademicWeek_ReferentialIdentity"()
RETURNS TRIGGER AS $func$
BEGIN
    IF TG_OP = 'INSERT' OR (OLD."School_SchoolId" IS DISTINCT FROM NEW."School_SchoolId" OR OLD."WeekIdentifier" IS DISTINCT FROM NEW."WeekIdentifier") THEN
        DELETE FROM "dms"."ReferentialIdentity"
        WHERE "DocumentId" = NEW."DocumentId" AND "ResourceKeyId" = 4;
        INSERT INTO "dms"."ReferentialIdentity" ("ReferentialId", "DocumentId", "ResourceKeyId")
        VALUES ("dms"."uuidv5"('edf1edf1-3df1-3df1-3df1-3df1edf1edf1'::uuid, 'Ed-FiAcademicWeek' || '$.schoolReference.schoolId=' || NEW."School_SchoolId"::text || '#' || '$.weekIdentifier=' || NEW."WeekIdentifier"::text), NEW."DocumentId", 4);
    END IF;
    RETURN NEW;
END;
$func$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS "TR_AcademicWeek_ReferentialIdentity" ON "edfi"."AcademicWeek";
CREATE TRIGGER "TR_AcademicWeek_ReferentialIdentity"
AFTER INSERT OR UPDATE ON "edfi"."AcademicWeek"
FOR EACH ROW
EXECUTE FUNCTION "edfi"."TF_TR_AcademicWeek_ReferentialIdentity"();

CREATE OR REPLACE FUNCTION "edfi"."TF_TR_AcademicWeek_Stamp"()
RETURNS TRIGGER AS $func$
DECLARE
    _stampedContentVersion bigint;
    _stampedContentLastModifiedAt timestamp with time zone;
BEGIN
    IF TG_OP = 'DELETE' THEN
        UPDATE "dms"."Document"
        SET "ContentVersion" = nextval('"dms"."ChangeVersionSequence"'), "ContentLastModifiedAt" = now()
        WHERE "DocumentId" = OLD."DocumentId";
        INSERT INTO "tracked_changes_edfi"."AcademicWeek" (
            "OldSchool_SchoolId",
            "OldWeekIdentifier",
            "Id",
            "ChangeVersion"
        )
        SELECT
            OLD."School_SchoolId",
            OLD."WeekIdentifier",
            doc."DocumentUuid",
            doc."ContentVersion"
        FROM "dms"."Document" doc
        WHERE doc."DocumentId" = OLD."DocumentId";
        RETURN OLD;
    END IF;
    IF TG_OP = 'UPDATE' AND NOT (OLD."DocumentId" IS DISTINCT FROM NEW."DocumentId" OR OLD."School_DocumentId" IS DISTINCT FROM NEW."School_DocumentId" OR OLD."School_SchoolId" IS DISTINCT FROM NEW."School_SchoolId" OR OLD."BeginDate" IS DISTINCT FROM NEW."BeginDate" OR OLD."EndDate" IS DISTINCT FROM NEW."EndDate" OR OLD."TotalInstructionalDays" IS DISTINCT FROM NEW."TotalInstructionalDays" OR OLD."WeekIdentifier" IS DISTINCT FROM NEW."WeekIdentifier") THEN
        RETURN NEW;
    END IF;
    IF TG_OP = 'INSERT' THEN
        SELECT "ContentVersion", "ContentLastModifiedAt"
        INTO STRICT _stampedContentVersion, _stampedContentLastModifiedAt
        FROM "dms"."Document"
        WHERE "DocumentId" = NEW."DocumentId";
        NEW."ContentVersion" := _stampedContentVersion;
        NEW."ContentLastModifiedAt" := _stampedContentLastModifiedAt;
    ELSIF TG_OP = 'UPDATE' THEN
        UPDATE "dms"."Document"
        SET "ContentVersion" = nextval('"dms"."ChangeVersionSequence"'), "ContentLastModifiedAt" = now()
        WHERE "DocumentId" = NEW."DocumentId"
        RETURNING "ContentVersion", "ContentLastModifiedAt" INTO STRICT _stampedContentVersion, _stampedContentLastModifiedAt;
        NEW."ContentVersion" := _stampedContentVersion;
        NEW."ContentLastModifiedAt" := _stampedContentLastModifiedAt;
    END IF;
    IF TG_OP = 'UPDATE' AND (OLD."School_SchoolId" IS DISTINCT FROM NEW."School_SchoolId" OR OLD."WeekIdentifier" IS DISTINCT FROM NEW."WeekIdentifier") THEN
        UPDATE "dms"."Document"
        SET "IdentityVersion" = nextval('"dms"."ChangeVersionSequence"'), "IdentityLastModifiedAt" = now()
        WHERE "DocumentId" = NEW."DocumentId";
        INSERT INTO "tracked_changes_edfi"."AcademicWeek" (
            "OldSchool_SchoolId",
            "OldWeekIdentifier",
            "NewSchool_SchoolId",
            "NewWeekIdentifier",
            "Id",
            "ChangeVersion"
        )
        SELECT
            OLD."School_SchoolId",
            OLD."WeekIdentifier",
            NEW."School_SchoolId",
            NEW."WeekIdentifier",
            doc."DocumentUuid",
            _stampedContentVersion
        FROM "dms"."Document" doc
        WHERE doc."DocumentId" = NEW."DocumentId";
    END IF;
    RETURN NEW;
END;
$func$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS "TR_AcademicWeek_Stamp" ON "edfi"."AcademicWeek";
CREATE TRIGGER "TR_AcademicWeek_Stamp"
BEFORE INSERT OR UPDATE OR DELETE ON "edfi"."AcademicWeek"
FOR EACH ROW
EXECUTE FUNCTION "edfi"."TF_TR_AcademicWeek_Stamp"();

