CREATE OR REPLACE FUNCTION "edfi"."TF_TR_InterventionPrescription_Stamp"()
RETURNS TRIGGER AS $func$
DECLARE
    _stampedContentVersion bigint;
    _stampedContentLastModifiedAt timestamp with time zone;
BEGIN
    IF TG_OP = 'DELETE' THEN
        UPDATE "dms"."Document"
        SET "ContentVersion" = nextval('"dms"."ChangeVersionSequence"'), "ContentLastModifiedAt" = now()
        WHERE "DocumentId" = OLD."DocumentId";
        INSERT INTO "tracked_changes_edfi"."InterventionPrescription" (
            "OldEducationOrganization_EducationOrganizationId",
            "OldInterventionPrescriptionIdentificationCode",
            "Id",
            "ChangeVersion"
        )
        SELECT
            OLD."EducationOrganization_EducationOrganizationId",
            OLD."InterventionPrescriptionIdentificationCode",
            doc."DocumentUuid",
            doc."ContentVersion"
        FROM "dms"."Document" doc
        WHERE doc."DocumentId" = OLD."DocumentId";
        RETURN OLD;
    END IF;
    IF TG_OP = 'UPDATE' AND NOT (OLD."DocumentId" IS DISTINCT FROM NEW."DocumentId" OR OLD."EducationOrganization_DocumentId" IS DISTINCT FROM NEW."EducationOrganization_DocumentId" OR OLD."EducationOrganization_EducationOrganizationId" IS DISTINCT FROM NEW."EducationOrganization_EducationOrganizationId" OR OLD."DeliveryMethodDescriptor_DescriptorId" IS DISTINCT FROM NEW."DeliveryMethodDescriptor_DescriptorId" OR OLD."InterventionClassDescriptor_DescriptorId" IS DISTINCT FROM NEW."InterventionClassDescriptor_DescriptorId" OR OLD."InterventionPrescriptionIdentificationCode" IS DISTINCT FROM NEW."InterventionPrescriptionIdentificationCode" OR OLD."MaxDosage" IS DISTINCT FROM NEW."MaxDosage" OR OLD."MinDosage" IS DISTINCT FROM NEW."MinDosage" OR OLD."Namespace" IS DISTINCT FROM NEW."Namespace") THEN
        RETURN NEW;
    END IF;
    IF TG_OP = 'INSERT' THEN
        SELECT "ContentVersion", "ContentLastModifiedAt"
        INTO STRICT _stampedContentVersion, _stampedContentLastModifiedAt
        FROM "dms"."Document"
        WHERE "DocumentId" = NEW."DocumentId";
        NEW."ContentVersion" := _stampedContentVersion;
        NEW."ContentLastModifiedAt" := _stampedContentLastModifiedAt;
    ELSIF TG_OP = 'UPDATE' THEN
        UPDATE "dms"."Document"
        SET "ContentVersion" = nextval('"dms"."ChangeVersionSequence"'), "ContentLastModifiedAt" = now()
        WHERE "DocumentId" = NEW."DocumentId"
        RETURNING "ContentVersion", "ContentLastModifiedAt" INTO STRICT _stampedContentVersion, _stampedContentLastModifiedAt;
        NEW."ContentVersion" := _stampedContentVersion;
        NEW."ContentLastModifiedAt" := _stampedContentLastModifiedAt;
    END IF;
    IF TG_OP = 'UPDATE' AND (OLD."EducationOrganization_EducationOrganizationId" IS DISTINCT FROM NEW."EducationOrganization_EducationOrganizationId" OR OLD."InterventionPrescriptionIdentificationCode" IS DISTINCT FROM NEW."InterventionPrescriptionIdentificationCode") THEN
        UPDATE "dms"."Document"
        SET "IdentityVersion" = nextval('"dms"."ChangeVersionSequence"'), "IdentityLastModifiedAt" = now()
        WHERE "DocumentId" = NEW."DocumentId";
        INSERT INTO "tracked_changes_edfi"."InterventionPrescription" (
            "OldEducationOrganization_EducationOrganizationId",
            "OldInterventionPrescriptionIdentificationCode",
            "NewEducationOrganization_EducationOrganizationId",
            "NewInterventionPrescriptionIdentificationCode",
            "Id",
            "ChangeVersion"
        )
        SELECT
            OLD."EducationOrganization_EducationOrganizationId",
            OLD."InterventionPrescriptionIdentificationCode",
            NEW."EducationOrganization_EducationOrganizationId",
            NEW."InterventionPrescriptionIdentificationCode",
            doc."DocumentUuid",
            _stampedContentVersion
        FROM "dms"."Document" doc
        WHERE doc."DocumentId" = NEW."DocumentId";
    END IF;
    RETURN NEW;
END;
$func$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS "TR_InterventionPrescription_Stamp" ON "edfi"."InterventionPrescription";
CREATE TRIGGER "TR_InterventionPrescription_Stamp"
BEFORE INSERT OR UPDATE OR DELETE ON "edfi"."InterventionPrescription"
FOR EACH ROW
EXECUTE FUNCTION "edfi"."TF_TR_InterventionPrescription_Stamp"();

