CREATE OR REPLACE FUNCTION "edfi"."TF_TR_LocalAccountReportingTag_Stamp"()
RETURNS TRIGGER AS $func$
BEGIN
    IF TG_OP = 'DELETE' THEN
        WITH stamped AS (
            UPDATE "dms"."Document"
            SET "ContentVersion" = nextval('"dms"."ChangeVersionSequence"'), "ContentLastModifiedAt" = now()
            WHERE "DocumentId" = OLD."LocalAccount_DocumentId"
            AND EXISTS (SELECT 1 FROM "edfi"."LocalAccount" r WHERE r."DocumentId" = OLD."LocalAccount_DocumentId")
            RETURNING "DocumentId", "ContentVersion", "ContentLastModifiedAt"
        )
        UPDATE "edfi"."LocalAccount" r
        SET "ContentVersion" = stamped."ContentVersion", "ContentLastModifiedAt" = stamped."ContentLastModifiedAt"
        FROM stamped
        WHERE r."DocumentId" = stamped."DocumentId";
        RETURN OLD;
    END IF;
    IF TG_OP = 'UPDATE' AND NOT (OLD."CollectionItemId" IS DISTINCT FROM NEW."CollectionItemId" OR OLD."LocalAccount_DocumentId" IS DISTINCT FROM NEW."LocalAccount_DocumentId" OR OLD."Ordinal" IS DISTINCT FROM NEW."Ordinal" OR OLD."ReportingTagDescriptor_DescriptorId" IS DISTINCT FROM NEW."ReportingTagDescriptor_DescriptorId" OR OLD."TagValue" IS DISTINCT FROM NEW."TagValue") THEN
        RETURN NEW;
    END IF;
    WITH stamped AS (
        UPDATE "dms"."Document"
        SET "ContentVersion" = nextval('"dms"."ChangeVersionSequence"'), "ContentLastModifiedAt" = now()
        WHERE "DocumentId" = NEW."LocalAccount_DocumentId"
        AND EXISTS (SELECT 1 FROM "edfi"."LocalAccount" r WHERE r."DocumentId" = NEW."LocalAccount_DocumentId")
        RETURNING "DocumentId", "ContentVersion", "ContentLastModifiedAt"
    )
    UPDATE "edfi"."LocalAccount" r
    SET "ContentVersion" = stamped."ContentVersion", "ContentLastModifiedAt" = stamped."ContentLastModifiedAt"
    FROM stamped
    WHERE r."DocumentId" = stamped."DocumentId";
    RETURN NEW;
END;
$func$ LANGUAGE plpgsql;

