CREATE OR REPLACE FUNCTION "edfi"."TF_TR_PostSecondaryEvent_Stamp"()
RETURNS TRIGGER AS $func$
DECLARE
    _stampedContentVersion bigint;
    _stampedContentLastModifiedAt timestamp with time zone;
BEGIN
    IF TG_OP = 'DELETE' THEN
        UPDATE "dms"."Document"
        SET "ContentVersion" = nextval('"dms"."ChangeVersionSequence"'), "ContentLastModifiedAt" = now()
        WHERE "DocumentId" = OLD."DocumentId";
        INSERT INTO "tracked_changes_edfi"."PostSecondaryEvent" (
            "OldEventDate",
            "OldPostSecondaryEventCategoryDescriptor_Namespace",
            "OldPostSecondaryEventCategoryDescriptor_CodeValue",
            "OldStudent_StudentUniqueId",
            "OldStudent_DocumentId",
            "Id",
            "ChangeVersion"
        )
        SELECT
            OLD."EventDate",
            oldDj0."Namespace",
            oldDj0."CodeValue",
            OLD."Student_StudentUniqueId",
            oldPj0s0."DocumentId",
            doc."DocumentUuid",
            doc."ContentVersion"
        FROM "dms"."Document" doc
        INNER JOIN "dms"."Descriptor" oldDj0 ON oldDj0."DocumentId" = OLD."PostSecondaryEventCategoryDescriptor_DescriptorId"
        INNER JOIN "edfi"."Student" oldPj0s0 ON oldPj0s0."DocumentId" = OLD."Student_DocumentId"
        WHERE doc."DocumentId" = OLD."DocumentId";
        RETURN OLD;
    END IF;
    IF TG_OP = 'UPDATE' AND NOT (OLD."DocumentId" IS DISTINCT FROM NEW."DocumentId" OR OLD."PostSecondaryInstitution_DocumentId" IS DISTINCT FROM NEW."PostSecondaryInstitution_DocumentId" OR OLD."PostSecondaryInstitution_PostSecondaryInstitutionId" IS DISTINCT FROM NEW."PostSecondaryInstitution_PostSecondaryInstitutionId" OR OLD."Student_DocumentId" IS DISTINCT FROM NEW."Student_DocumentId" OR OLD."Student_StudentUniqueId" IS DISTINCT FROM NEW."Student_StudentUniqueId" OR OLD."PostSecondaryEventCategoryDescriptor_DescriptorId" IS DISTINCT FROM NEW."PostSecondaryEventCategoryDescriptor_DescriptorId" OR OLD."EventDate" IS DISTINCT FROM NEW."EventDate") THEN
        RETURN NEW;
    END IF;
    IF TG_OP = 'INSERT' THEN
        SELECT "ContentVersion", "ContentLastModifiedAt"
        INTO STRICT _stampedContentVersion, _stampedContentLastModifiedAt
        FROM "dms"."Document"
        WHERE "DocumentId" = NEW."DocumentId";
        NEW."ContentVersion" := _stampedContentVersion;
        NEW."ContentLastModifiedAt" := _stampedContentLastModifiedAt;
    ELSIF TG_OP = 'UPDATE' THEN
        UPDATE "dms"."Document"
        SET "ContentVersion" = nextval('"dms"."ChangeVersionSequence"'), "ContentLastModifiedAt" = now()
        WHERE "DocumentId" = NEW."DocumentId"
        RETURNING "ContentVersion", "ContentLastModifiedAt" INTO STRICT _stampedContentVersion, _stampedContentLastModifiedAt;
        NEW."ContentVersion" := _stampedContentVersion;
        NEW."ContentLastModifiedAt" := _stampedContentLastModifiedAt;
    END IF;
    IF TG_OP = 'UPDATE' AND (OLD."EventDate" IS DISTINCT FROM NEW."EventDate" OR OLD."PostSecondaryEventCategoryDescriptor_DescriptorId" IS DISTINCT FROM NEW."PostSecondaryEventCategoryDescriptor_DescriptorId" OR OLD."Student_StudentUniqueId" IS DISTINCT FROM NEW."Student_StudentUniqueId") THEN
        UPDATE "dms"."Document"
        SET "IdentityVersion" = nextval('"dms"."ChangeVersionSequence"'), "IdentityLastModifiedAt" = now()
        WHERE "DocumentId" = NEW."DocumentId";
        INSERT INTO "tracked_changes_edfi"."PostSecondaryEvent" (
            "OldEventDate",
            "OldPostSecondaryEventCategoryDescriptor_Namespace",
            "OldPostSecondaryEventCategoryDescriptor_CodeValue",
            "OldStudent_StudentUniqueId",
            "OldStudent_DocumentId",
            "NewEventDate",
            "NewPostSecondaryEventCategoryDescriptor_Namespace",
            "NewPostSecondaryEventCategoryDescriptor_CodeValue",
            "NewStudent_StudentUniqueId",
            "NewStudent_DocumentId",
            "Id",
            "ChangeVersion"
        )
        SELECT
            OLD."EventDate",
            oldDj0."Namespace",
            oldDj0."CodeValue",
            OLD."Student_StudentUniqueId",
            oldPj0s0."DocumentId",
            NEW."EventDate",
            newDj0."Namespace",
            newDj0."CodeValue",
            NEW."Student_StudentUniqueId",
            newPj0s0."DocumentId",
            doc."DocumentUuid",
            _stampedContentVersion
        FROM "dms"."Document" doc
        INNER JOIN "dms"."Descriptor" oldDj0 ON oldDj0."DocumentId" = OLD."PostSecondaryEventCategoryDescriptor_DescriptorId"
        INNER JOIN "edfi"."Student" oldPj0s0 ON oldPj0s0."DocumentId" = OLD."Student_DocumentId"
        INNER JOIN "dms"."Descriptor" newDj0 ON newDj0."DocumentId" = NEW."PostSecondaryEventCategoryDescriptor_DescriptorId"
        INNER JOIN "edfi"."Student" newPj0s0 ON newPj0s0."DocumentId" = NEW."Student_DocumentId"
        WHERE doc."DocumentId" = NEW."DocumentId";
    END IF;
    RETURN NEW;
END;
$func$ LANGUAGE plpgsql;

