CREATE OR REPLACE FUNCTION "edfi"."TF_TR_StaffLeave_Stamp"()
RETURNS TRIGGER AS $func$
DECLARE
    _stampedContentVersion bigint;
    _stampedContentLastModifiedAt timestamp with time zone;
BEGIN
    IF TG_OP = 'DELETE' THEN
        UPDATE "dms"."Document"
        SET "ContentVersion" = nextval('"dms"."ChangeVersionSequence"'), "ContentLastModifiedAt" = now()
        WHERE "DocumentId" = OLD."DocumentId";
        INSERT INTO "tracked_changes_edfi"."StaffLeave" (
            "OldBeginDate",
            "OldStaffLeaveEventCategoryDescriptor_Namespace",
            "OldStaffLeaveEventCategoryDescriptor_CodeValue",
            "OldStaff_StaffUniqueId",
            "OldStaff_DocumentId",
            "Id",
            "ChangeVersion"
        )
        SELECT
            OLD."BeginDate",
            oldDj0."Namespace",
            oldDj0."CodeValue",
            OLD."Staff_StaffUniqueId",
            oldPj0s0."DocumentId",
            doc."DocumentUuid",
            doc."ContentVersion"
        FROM "dms"."Document" doc
        INNER JOIN "dms"."Descriptor" oldDj0 ON oldDj0."DocumentId" = OLD."StaffLeaveEventCategoryDescriptor_DescriptorId"
        INNER JOIN "edfi"."Staff" oldPj0s0 ON oldPj0s0."DocumentId" = OLD."Staff_DocumentId"
        WHERE doc."DocumentId" = OLD."DocumentId";
        RETURN OLD;
    END IF;
    IF TG_OP = 'UPDATE' AND NOT (OLD."DocumentId" IS DISTINCT FROM NEW."DocumentId" OR OLD."Staff_DocumentId" IS DISTINCT FROM NEW."Staff_DocumentId" OR OLD."Staff_StaffUniqueId" IS DISTINCT FROM NEW."Staff_StaffUniqueId" OR OLD."StaffLeaveEventCategoryDescriptor_DescriptorId" IS DISTINCT FROM NEW."StaffLeaveEventCategoryDescriptor_DescriptorId" OR OLD."BeginDate" IS DISTINCT FROM NEW."BeginDate" OR OLD."EndDate" IS DISTINCT FROM NEW."EndDate" OR OLD."Reason" IS DISTINCT FROM NEW."Reason" OR OLD."SubstituteAssigned" IS DISTINCT FROM NEW."SubstituteAssigned") THEN
        RETURN NEW;
    END IF;
    IF TG_OP = 'INSERT' THEN
        SELECT "ContentVersion", "ContentLastModifiedAt"
        INTO STRICT _stampedContentVersion, _stampedContentLastModifiedAt
        FROM "dms"."Document"
        WHERE "DocumentId" = NEW."DocumentId";
        NEW."ContentVersion" := _stampedContentVersion;
        NEW."ContentLastModifiedAt" := _stampedContentLastModifiedAt;
    ELSIF TG_OP = 'UPDATE' THEN
        UPDATE "dms"."Document"
        SET "ContentVersion" = nextval('"dms"."ChangeVersionSequence"'), "ContentLastModifiedAt" = now()
        WHERE "DocumentId" = NEW."DocumentId"
        RETURNING "ContentVersion", "ContentLastModifiedAt" INTO STRICT _stampedContentVersion, _stampedContentLastModifiedAt;
        NEW."ContentVersion" := _stampedContentVersion;
        NEW."ContentLastModifiedAt" := _stampedContentLastModifiedAt;
    END IF;
    IF TG_OP = 'UPDATE' AND (OLD."BeginDate" IS DISTINCT FROM NEW."BeginDate" OR OLD."StaffLeaveEventCategoryDescriptor_DescriptorId" IS DISTINCT FROM NEW."StaffLeaveEventCategoryDescriptor_DescriptorId" OR OLD."Staff_StaffUniqueId" IS DISTINCT FROM NEW."Staff_StaffUniqueId") THEN
        UPDATE "dms"."Document"
        SET "IdentityVersion" = nextval('"dms"."ChangeVersionSequence"'), "IdentityLastModifiedAt" = now()
        WHERE "DocumentId" = NEW."DocumentId";
        INSERT INTO "tracked_changes_edfi"."StaffLeave" (
            "OldBeginDate",
            "OldStaffLeaveEventCategoryDescriptor_Namespace",
            "OldStaffLeaveEventCategoryDescriptor_CodeValue",
            "OldStaff_StaffUniqueId",
            "OldStaff_DocumentId",
            "NewBeginDate",
            "NewStaffLeaveEventCategoryDescriptor_Namespace",
            "NewStaffLeaveEventCategoryDescriptor_CodeValue",
            "NewStaff_StaffUniqueId",
            "NewStaff_DocumentId",
            "Id",
            "ChangeVersion"
        )
        SELECT
            OLD."BeginDate",
            oldDj0."Namespace",
            oldDj0."CodeValue",
            OLD."Staff_StaffUniqueId",
            oldPj0s0."DocumentId",
            NEW."BeginDate",
            newDj0."Namespace",
            newDj0."CodeValue",
            NEW."Staff_StaffUniqueId",
            newPj0s0."DocumentId",
            doc."DocumentUuid",
            _stampedContentVersion
        FROM "dms"."Document" doc
        INNER JOIN "dms"."Descriptor" oldDj0 ON oldDj0."DocumentId" = OLD."StaffLeaveEventCategoryDescriptor_DescriptorId"
        INNER JOIN "edfi"."Staff" oldPj0s0 ON oldPj0s0."DocumentId" = OLD."Staff_DocumentId"
        INNER JOIN "dms"."Descriptor" newDj0 ON newDj0."DocumentId" = NEW."StaffLeaveEventCategoryDescriptor_DescriptorId"
        INNER JOIN "edfi"."Staff" newPj0s0 ON newPj0s0."DocumentId" = NEW."Staff_DocumentId"
        WHERE doc."DocumentId" = NEW."DocumentId";
    END IF;
    RETURN NEW;
END;
$func$ LANGUAGE plpgsql;

