CREATE OR REPLACE FUNCTION "edfi"."TF_TR_SurveyResponseSurveyLevel_Stamp"()
RETURNS TRIGGER AS $func$
BEGIN
    IF TG_OP = 'DELETE' THEN
        WITH stamped AS (
            UPDATE "dms"."Document"
            SET "ContentVersion" = nextval('"dms"."ChangeVersionSequence"'), "ContentLastModifiedAt" = now()
            WHERE "DocumentId" = OLD."SurveyResponse_DocumentId"
            AND EXISTS (SELECT 1 FROM "edfi"."SurveyResponse" r WHERE r."DocumentId" = OLD."SurveyResponse_DocumentId")
            RETURNING "DocumentId", "ContentVersion", "ContentLastModifiedAt"
        )
        UPDATE "edfi"."SurveyResponse" r
        SET "ContentVersion" = stamped."ContentVersion", "ContentLastModifiedAt" = stamped."ContentLastModifiedAt"
        FROM stamped
        WHERE r."DocumentId" = stamped."DocumentId";
        RETURN OLD;
    END IF;
    IF TG_OP = 'UPDATE' AND NOT (OLD."CollectionItemId" IS DISTINCT FROM NEW."CollectionItemId" OR OLD."Ordinal" IS DISTINCT FROM NEW."Ordinal" OR OLD."SurveyResponse_DocumentId" IS DISTINCT FROM NEW."SurveyResponse_DocumentId" OR OLD."SurveyLevelDescriptor_DescriptorId" IS DISTINCT FROM NEW."SurveyLevelDescriptor_DescriptorId") THEN
        RETURN NEW;
    END IF;
    WITH stamped AS (
        UPDATE "dms"."Document"
        SET "ContentVersion" = nextval('"dms"."ChangeVersionSequence"'), "ContentLastModifiedAt" = now()
        WHERE "DocumentId" = NEW."SurveyResponse_DocumentId"
        AND EXISTS (SELECT 1 FROM "edfi"."SurveyResponse" r WHERE r."DocumentId" = NEW."SurveyResponse_DocumentId")
        RETURNING "DocumentId", "ContentVersion", "ContentLastModifiedAt"
    )
    UPDATE "edfi"."SurveyResponse" r
    SET "ContentVersion" = stamped."ContentVersion", "ContentLastModifiedAt" = stamped."ContentLastModifiedAt"
    FROM stamped
    WHERE r."DocumentId" = stamped."DocumentId";
    RETURN NEW;
END;
$func$ LANGUAGE plpgsql;

